/// 对已经落盘的图片进行读取，然后入库
#[cfg(not(target_os = "android"))]
pub async fn postprocess_downloaded_image(
    dq: &DownloadQueue,
    id: u64,
    path: &Path,
    url: &str,
    plugin_id: &str,
    task_id: Option<&str>,
    failed_image_id: Option<i64>,
    surf_record_id: Option<&str>,
    download_start_time: u64,
    output_album_id: Option<&str>,
    http_headers: &HashMap<String, String>,
    native: bool,
    custom_display_name: Option<&str>,
    metadata_id: Option<i64>,
) -> Result<bool, String> {
    let path_used = ensure_media_extension_by_infer(path).await;
    let path = path_used.as_path();
    let bytes = match tokio::fs::read(path).await {
        Ok(bytes) => bytes,
        Err(e) => {
            let err = format!("Failed to read file: {}", e);
            let event_task_id = task_id.or(surf_record_id).unwrap_or_default();
            if let Some(task_id) = task_id {
                upsert_failed_image_on_failure(
                    failed_image_id,
                    task_id,
                    plugin_id,
                    url,
                    download_start_time as i64,
                    err.as_str(),
                    http_headers,
                    metadata_id,
                    custom_display_name,
                );
            }
            dq.emit_state(
                event_task_id,
                id,
                url,
                download_start_time,
                plugin_id,
                DownloadState::Failed,
                Some(err.as_str()),
                failed_image_id,
                native,
            );
            if let Some(task_id) = task_id {
                GlobalEmitter::global().emit_task_status_from_storage(task_id);
            }
            return Err(err);
        }
    };
    postprocess_downloaded_image_bytes(
        dq,
        id,
        PostprocessImageBytesTarget::ExistingPath(path),
        &bytes,
        url,
        plugin_id,
        task_id,
        failed_image_id,
        surf_record_id,
        download_start_time,
        output_album_id,
        http_headers,
        native,
        custom_display_name,
        metadata_id,
    )
    .await
}

