pub async fn download_with_retry(
    dq: &DownloadQueue,
    task_id: &str,
    url_str: &str,
    headers: &HashMap<String, String>,
    download_id: u64,
) -> Result<DownloadOutcome, String> {
    let max_attempts = Settings::global().get_download_max_retries().max(1);
    let url = Url::parse(url_str).map_err(|e| format!("invalid url: {e}"))?;
    let downloader = get_downloader_for_url(&url)
        .ok_or_else(|| format!("no downloader for scheme: {}", url.scheme()))?;
    let mut sink = DownloadSink::new(download_id);

    for attempt in 1..=max_attempts {
        if dq.is_download_canceled(task_id).await {
            sink.clear().await;
            return Err("Task canceled".to_string());
        }

        match downloader.download(dq, &url, task_id, headers, &mut sink, download_id).await {
            Ok(()) => return sink.finalize().await,
            Err(e) => {
                if !e.is_retryable() || attempt >= max_attempts {
                    sink.clear().await;
                    return Err(e.into_message());
                }
                e.emit_retry_log(task_id, attempt, max_attempts);
                if e.should_clear() {
                    sink.clear().await;
                }
                sleep(Duration::from_millis(500 * attempt as u64)).await;
            }
        }
    }
    unreachable!()
}
