            let dir = crate::app_paths::AppPaths::global().downloads_temp_dir();
            tokio::fs::create_dir_all(&dir).await.map_err(|e| format!("create downloads temp dir: {e}"))?;
            let path = dir.join(format!("{}.part", self.download_id));
            let file = tokio::fs::File::create(&path).await.map_err(|e| format!("create spill file: {e}"))?;
            self.temp_path = Some(path);
            self.temp_file = Some(file);
        }
        if let Some(ref mut file) = self.temp_file {
            use tokio::io::AsyncWriteExt;
            file.write_all(&self.buffer).await.map_err(|e| format!("write spill file: {e}"))?;
            self.spilled_len += self.buffer.len() as u64;
            self.buffer.clear();
        }
        Ok(())
    }

    pub(crate) async fn clear(&mut self) {
        self.buffer.clear();
        self.spilled_len = 0;
        if let Some(mut file) = self.temp_file.take() {
            use tokio::io::AsyncWriteExt;
            let _ = file.shutdown().await;
            drop(file);
        }
        if let Some(ref path) = self.temp_path.take() {
            let _ = tokio::fs::remove_file(path).await;
        }
    }

    pub(crate) async fn finalize(mut self) -> Result<DownloadOutcome, String> {
        if let Some(mut file) = self.temp_file.take() {
            use tokio::io::AsyncWriteExt;
            if !self.buffer.is_empty() {
                file.write_all(&self.buffer).await.map_err(|e| format!("flush spill buffer: {e}"))?;
                self.spilled_len += self.buffer.len() as u64;
            }
            file.shutdown().await.map_err(|e| format!("close spill file: {e}"))?;
            drop(file);
            let path = self.temp_path.take().unwrap();
            return Ok(DownloadOutcome::Path(path));
        }
        Ok(DownloadOutcome::Bytes(self.buffer))
    }
}
